func opActionsGetActionsId(r *shell.Runner, w *audit.Writer) *cli.Command {
	return &cli.Command{
		Name:      "get-actions-id",
		Usage:     "Get an Action",
		ArgsUsage: "<id>",
		Flags: []cli.Flag{
			&cli.StringFlag{Name: "display", Usage: "query: "},
			&cli.StringFlag{Name: "entities", Usage: "query: "},
			&cli.StringFlag{Name: "fields", Usage: "query: `all` or a comma-separated list of action [fields](/cloud/trello/guides/rest-ap…"},
			&cli.StringFlag{Name: "member", Usage: "query: "},
			&cli.StringFlag{Name: "member_fields", Usage: "query: `all` or a comma-separated list of member [fields](/cloud/trello/guides/rest-ap…"},
			&cli.StringFlag{Name: "memberCreator", Usage: "query: Whether to include the member object for the creator of the action"},
			&cli.StringFlag{Name: "memberCreator_fields", Usage: "query: `all` or a comma-separated list of member [fields](/cloud/trello/guides/rest-ap…"},
		},
		Action: verb.Wrap(
			verb.Spec{
				Name: "ops.trello.actions.get-actions-id",
				ArgsFunc: func(c *cli.Command) (map[string]string, []string) {
					m := map[string]string{}
					if c.IsSet("display") {
						m["--display"] = c.String("display")
					}
					if c.IsSet("entities") {
						m["--entities"] = c.String("entities")
					}
					if c.IsSet("fields") {
						m["--fields"] = c.String("fields")
					}
					if c.IsSet("member") {
						m["--member"] = c.String("member")
					}
					if c.IsSet("member_fields") {
						m["--member_fields"] = c.String("member_fields")
					}
					if c.IsSet("memberCreator") {
						m["--memberCreator"] = c.String("memberCreator")
					}
					if c.IsSet("memberCreator_fields") {
						m["--memberCreator_fields"] = c.String("memberCreator_fields")
					}
					return m, c.Args().Slice()
				},
				Action: func(ctx context.Context, c *cli.Command) error {
					args := c.Args().Slice()
					if len(args) != 1 {
						return fmt.Errorf("trello: need 1 positional args (id), got %d", len(args))
					}
					p0 := url.PathEscape(args[0])
					path := "/actions/" + p0
					q := url.Values{}
					if c.IsSet("display") {
						q.Set("display", c.String("display"))
					}
					if c.IsSet("entities") {
						q.Set("entities", c.String("entities"))
					}
					if c.IsSet("fields") {
						q.Set("fields", c.String("fields"))
					}
					if c.IsSet("member") {
						q.Set("member", c.String("member"))
					}
					if c.IsSet("member_fields") {
						q.Set("member_fields", c.String("member_fields"))
					}
					if c.IsSet("memberCreator") {
						q.Set("memberCreator", c.String("memberCreator"))
					}
					if c.IsSet("memberCreator_fields") {
						q.Set("memberCreator_fields", c.String("memberCreator_fields"))
					}
					var body []byte
					return doRequestAndStream(ctx, r, "GET", path, q, body, true)
				},
			},
			w,
		),
	}
}

